query:
UPDATE v2Stages SET stageName='暗草惊弓', weaponEmoji='🏹', storyBefore='林暗草深，夜风乍起。「林暗草惊风，将军夜引弓。」——卢纶《塞下曲》中的将军幻影出现在你面前，一张惊弓指向未知的黑暗。你必须以诗词之力，辨清虚实，方能继续前行。', storyAfter='暗草惊弓射出，林中的幻影纷纷消散。你的判断力在这场考验中得到磨砺，九霄之路渐渐清晰。' WHERE stageNumber=8;
UPDATE v2Stages SET stageName='九霄雷符', weaponEmoji='🌩️', storyBefore='仰望苍穹，雷光如龙蟠绕。「愿乘泠风去，直上九霄天。」——李白《登太白峰》中的豪情化为一道雷符，只有胸怀凌云之志的人，才能驾驭这股天地之力。', storyAfter='九霄雷符激活，天地震动！第三章九霄惊雷完成，你已掌握突破次元的雷法，距离樊登又近了三步。' WHERE stageNumber=9;
UPDATE v2Stages SET stageName='谪仙青莲', weaponEmoji='🌊', storyBefore='进入李商隐的瑰丽幻境，现实与虚幻交替。「停杯投箸不能食，拔剑四顾心茫然。」——李白《行路难》中的迷茫化为第一道考验。在这片幻境中，你必须保持清醒，找到真实的出路。', storyAfter='青莲之气护身，幻境中的第一层迷雾散去。谪仙的豪情在你心中燃起，继续探索这片奇幻之地。' WHERE stageNumber=10;
UPDATE v2Stages SET stageName='太极吴钩', weaponEmoji='⚔️', storyBefore='幻境深处，一把古朴的吴钩横亘在路中央。「男儿事长君，大羽正辞亲。」——李颀《古意》中的男儿气概化为这把吴钩的锋芒。只有真正懂得担当的人，才能挥动它。', storyAfter='太极吴钩在手，阴阳之力平衡。幻境中的虚实之战进入关键阶段，你的意志愈发坚定。' WHERE stageNumber=11;
UPDATE v2Stages SET stageName='不死灵药', weaponEmoji='💊', storyBefore='幻境最深处，月光如水，嫦娥的身影若隐若现。「嫦娥应悔偷灵药，碧海青天夜夜心。」——李商隐《嫦娥》中的悔恨化为一瓶不死灵药。取之，还是舍之？这是你的选择。', storyAfter='不死灵药入手，第四章沧海幻梦完成。你在虚实交替中磨砺了意志，幻境的枷锁已然松动。' WHERE stageNumber=12;
UPDATE v2Stages SET stageName='沧海月珠', weaponEmoji='🌙', storyBefore='须弥世界的入口处，一颗月珠悬浮在沧海之上。「沧海月明珠有泪，蓝田日暖玉生烟。」——李商隐《锦瑟》中的意象化为现实。这颗月珠是打开须弥之门的钥匙。', storyAfter='沧海月珠在手，须弥世界的大门缓缓开启。万千世界在你眼前展开，佛道玄机即将揭晓。' WHERE stageNumber=13;
UPDATE v2Stages SET stageName='须弥像素印', weaponEmoji='🔮', storyBefore='须弥世界中，大与小、多与少的界限消失了。「须弥藏芥子，芥子纳须弥。」——王维禅诗的意象在此化为一枚神奇的像素印，能将万千世界收纳于方寸之间。', storyAfter='须弥像素印激活，世界在你掌心收缩又扩张。你已领悟佛道玄机的第二层境界，继续前行。' WHERE stageNumber=14;

